xpath.script:
// 
(function () {
    var html = document.documentElement;
    var search = window.location.search || '';
    var lang = html.getAttribute('lang') || '';
    var flashDebug = false;
    var preloadReleased = false;
    html.classList.add('alaj-site-theme');
    try {
        flashDebug = new window.URLSearchParams(search).has('flash_debug');
    } catch (error) {
        flashDebug = search.indexOf('flash_debug') !== -1;
    }
    if (lang.indexOf('ar') === 0) {
        html.setAttribute('dir', 'rtl');
    } else {
        html.setAttribute('dir', 'ltr');
    }

    function checkLoginPage() {
        var loginForm = document.querySelector('.oe_login_form');
        if (loginForm) {
            var ww = document.getElementById('wrapwrap');
            if (ww) ww.classList.add('alaj-login-active');
        }
    }

    function isEditorPreview() {
        try {
            if (window.top !== window) {
                return true;
            }
        } catch (error) {
            return true;
        }
        return !!(document.body && document.body.classList.contains('editor_enable'));
    }

    function releasePreload() {
        if (preloadReleased) {
            return;
        }
        function done() {
            preloadReleased = true;
            html.classList.remove('alaj-preload');
        }
        if (flashDebug) {
            done();
            return;
        }
        if (isEditorPreview() && document.readyState !== 'complete') {
            window.addEventListener('load', releasePreload, { once: true });
            return;
        }
        var afterPaint = function () {
            if (isEditorPreview()) {
                window.setTimeout(done, 180);
            } else {
                done();
            }
        };
        if (window.requestAnimationFrame) {
            window.requestAnimationFrame(function () {
                window.requestAnimationFrame(afterPaint);
            });
        } else {
            window.setTimeout(afterPaint, 0);
        }
    }

    function describeElement(el) {
        if (!el || !el.getBoundingClientRect) return null;
        var rect = el.getBoundingClientRect();
        var style = window.getComputedStyle(el);
        return {
            element: el.tagName.toLowerCase() + (el.id ? '#' + el.id : '') + (el.className ? '.' + String(el.className).trim().replace(/\s+/g, '.') : ''),
            rect: {
                x: Math.round(rect.x),
                y: Math.round(rect.y),
                w: Math.round(rect.width),
                h: Math.round(rect.height),
            },
            position: style.position,
            display: style.display,
            visibility: style.visibility,
            opacity: style.opacity,
            zIndex: style.zIndex,
            background: style.backgroundImage !== 'none' ? style.backgroundImage : style.backgroundColor,
        };
    }

    function initFlashProbe() {
        if (!flashDebug || !window.console) return;
        var samplePoints = function () {
            return [
                [Math.max(12, Math.round(window.innerWidth * 0.15)), 24],
                [Math.round(window.innerWidth * 0.5), 80],
                [Math.round(window.innerWidth * 0.5), Math.round(window.innerHeight * 0.35)],
            ];
        };
        function logStage(label) {
            if (!document.body || !document.elementsFromPoint) return;
            var seen = [];
            var rows = [];
            Array.prototype.forEach.call(samplePoints(), function (point) {
                Array.prototype.forEach.call(document.elementsFromPoint(point[0], point[1]).slice(0, 6), function (el) {
                    if (!el || seen.indexOf(el) !== -1) return;
                    seen.push(el);
                    var desc = describeElement(el);
                    if (desc) rows.push(desc);
                });
            });
            console.groupCollapsed('[ALAJ FLASH PROBE]', label, window.location.pathname);
            console.table(rows);
            console.log('toolbarExpanded', !!document.querySelector('.o_main_navbar'));
            console.log('resourceTimings', performance.getEntriesByType('resource').filter(function (entry) {
                return /\.css($|\?)/.test(entry.name) || /fonts\.googleapis|fonts\.gstatic/.test(entry.name);
            }).map(function (entry) {
                return { name: entry.name, duration: Math.round(entry.duration) };
            }));
            console.groupEnd();
        }
        document.addEventListener('click', function (event) {
            var trigger = null;
            if (event.target) {
                if (event.target.closest) {
                    trigger = event.target.closest('a[href], button');
                }
            }
            if (!trigger) return;
            console.log('[ALAJ FLASH PROBE] click', {
                path: window.location.pathname,
                target: trigger.outerHTML ? trigger.outerHTML.slice(0, 180) : trigger.tagName,
            });
            logStage('before-nav');
            window.setTimeout(function () { logStage('after-120ms'); }, 120);
            window.setTimeout(function () { logStage('after-260ms'); }, 260);
        }, true);
        if (window.MutationObserver) {
            var mutationTimer = null;
            var mutationObserver = new MutationObserver(function () {
                window.clearTimeout(mutationTimer);
                mutationTimer = window.setTimeout(function () {
                    logStage('mutation');
                }, 50);
            });
            var observeBody = function () {
                if (!document.body) return;
                mutationObserver.observe(document.body, {
                    subtree: true,
                    childList: true,
                    attributes: true,
                    attributeFilter: ['class', 'style'],
                });
            };
            if (document.body) observeBody();
            else document.addEventListener('DOMContentLoaded', observeBody, { once: true });
        }
        window.addEventListener('pageshow', function () { logStage('pageshow'); });
        window.addEventListener('load', function () { logStage('load'); });
    }

    function initMobileDrawer() {
        try {
            var drawer = document.querySelector('.alaj-drawer');
            var backdrop = document.querySelector('.alaj-drawer-backdrop');
            if (!drawer || !backdrop || drawer.dataset.alajDrawerReady === '1') return;
            drawer.dataset.alajDrawerReady = '1';

            function setDrawerState(isOpen) {
                drawer.classList.toggle('show', isOpen);
                backdrop.classList.toggle('show', isOpen);
                document.body.style.overflow = isOpen ? 'hidden' : '';
            }

            Array.prototype.forEach.call(document.querySelectorAll('[data-alaj-drawer-open]'), function (btn) {
                btn.addEventListener('click', function () { setDrawerState(true); });
            });
            Array.prototype.forEach.call(document.querySelectorAll('[data-alaj-drawer-close]'), function (btn) {
                btn.addEventListener('click', function () { setDrawerState(false); });
            });

            var drawerLinks = drawer.querySelectorAll ? drawer.querySelectorAll('a[href]') : [];
            Array.prototype.forEach.call(drawerLinks, function (link) {
                link.addEventListener('click', function () { setDrawerState(false); });
            });

            document.addEventListener('keydown', function (e) {
                if (e.key === 'Escape') setDrawerState(false);
            });
        } catch (error) {
            console.warn('ALAJ drawer init skipped:', error);
        }
    }

    function initNavigationCloak() {
        if (html.dataset.alajNavCloakReady === '1') {
            return;
        }
        html.dataset.alajNavCloakReady = '1';

        var clearTimer = null;
        function getNavigationLink(target) {
            var link = target && target.closest ? target.closest('a[href]') : null;
            if (!link) return null;
            if (link.hasAttribute('download')) return null;

            var targetAttr = link.getAttribute('target');
            if (targetAttr && targetAttr !== '_self') return null;
            if (link.dataset.bsToggle || link.getAttribute('data-bs-toggle') || link.getAttribute('data-toggle')) return null;

            var href = (link.getAttribute('href') || '').trim();
            if (!href || href.charAt(0) === '#') return null;
            if (/^(mailto:|tel:|javascript:)/i.test(href)) return null;

            try {
                var url = new window.URL(link.href, window.location.href);
                if (url.origin !== window.location.origin) return null;

                var nextLocation = url.pathname + url.search;
                var currentLocation = window.location.pathname + window.location.search;
                if (nextLocation === currentLocation && url.hash) return null;
            } catch (error) {
                return null;
            }
            return link;
        }

        function clearCloak() {
            window.clearTimeout(clearTimer);
            html.classList.remove('alaj-nav-transitioning');
        }

        function armCloak() {
            html.classList.add('alaj-nav-transitioning');
            window.clearTimeout(clearTimer);
            clearTimer = window.setTimeout(clearCloak, 3000);
        }

        document.addEventListener('click', function (event) {
            if (event.defaultPrevented || event.button !== 0) return;
            if (event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) return;
            if (!getNavigationLink(event.target)) return;
            armCloak();
        }, true);

        document.addEventListener('submit', function (event) {
            if (event.defaultPrevented) return;
            var form = event.target;
            if (!form || form.tagName !== 'FORM') return;

            var action = (form.getAttribute('action') || window.location.href).trim();
            if (!action) return;

            try {
                var actionUrl = new window.URL(action, window.location.href);
                if (actionUrl.origin !== window.location.origin) return;
            } catch (error) {
                return;
            }

            armCloak();
        }, true);

        window.addEventListener('pageshow', clearCloak);
        window.addEventListener('load', function () {
            window.setTimeout(clearCloak, 0);
        }, { once: true });
    }

    function boot() {
        try {
            checkLoginPage();
            initNavigationCloak();
            initMobileDrawer();
        } finally {
            releasePreload();
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', boot);
    } else {
        boot();
    }
    window.addEventListener('load', boot);
    window.addEventListener('pageshow', releasePreload);
    initFlashProbe();
})();
//
